    act_zip VARCHAR(6),
    act_eml VARCHAR(30),
    act_www VARCHAR(30),
    act_pgr VARCHAR(30),
    act_mbl VARCHAR(30),
    act_dsg VARCHAR(30),
    act_typ VARCHAR(4),
    dbt_dis NUMERIC(7, 2),
    dbt_mcp NUMERIC(7, 2),
    dbt_typ VARCHAR(1),
    dbt_rap VARCHAR(1),
    rou_idy VARCHAR(15),
    mdl_req VARCHAR(1),
    mcl_req VARCHAR(1),
    crt_mdl NUMERIC(15, 2),
    crt_ppd NUMERIC(7, 2),
    dbt_mcl NUMERIC(15, 2),
    loc_idy VARCHAR(10),
