    acn_one VARCHAR(15),
    bnm_one VARCHAR(30),
    bbn_one VARCHAR(30),
    acn_two VARCHAR(15),
    bnm_two VARCHAR(30),
    bbn_two VARCHAR(30),
    cat_idy VARCHAR(10),
    key_act VARCHAR(1),
    cst_typ VARCHAR(15),
    ret_typ VARCHAR(15),
    van_cap INTEGER,
    act_doc DATE,
    sku_rng NUMERIC(15, 2),
    gcc_id VARCHAR(25),
    _nullflags TEXT
);

