-- Table: agd (Migrated from AGD.DBF)
DROP TABLE IF EXISTS agd CASCADE;
CREATE TABLE agd (
    inv_idy VARCHAR(10),
    inv_dat DATE,
    due_dat DATE,
    cst_idy VARCHAR(10),
    net_amt NUMERIC(15, 2),
    day_ovr INTEGER,
    txn_typ VARCHAR(3),
    _nullflags TEXT
);

-- No records found in AGD.DBF

-- Table: asm (Migrated from ASM.DBF)
DROP TABLE IF EXISTS asm CASCADE;
CREATE TABLE asm (
    asm_idy VARCHAR(10),
    asm_nme VARCHAR(40),
    att_idy VARCHAR(10),
    asm_val NUMERIC(15, 2),
    act_idy VARCHAR(10),
    asm_dpv NUMERIC(15, 2),
    asm_cid VARCHAR(10),
    asm_lfp INTEGER,
    mfg_idy VARCHAR(10),
    asm_tsp TEXT,
    asm_qty NUMERIC(15, 2),
    ind_idy VARCHAR(1),
    asm_cap NUMERIC(15, 2),
    _nullflags TEXT
);

-- No records found in ASM.DBF

-- Table: avt (Migrated from AVT.DBF)
DROP TABLE IF EXISTS avt CASCADE;
CREATE TABLE avt (
    inv_idy VARCHAR(10),
    inv_dat DATE,
    prd_idy VARCHAR(10),
    cat_idy VARCHAR(10),
    mbl_idy VARCHAR(20),
    smn_idy VARCHAR(10),
    smn_mbl VARCHAR(20),
    avt_idy VARCHAR(10),
    avt_sts VARCHAR(10),
    caf_sts VARCHAR(10),
    chr_sts VARCHAR(10),
    chr_dat DATE,
    sal_idy VARCHAR(10),
    sal_dat DATE,
    cst_idy VARCHAR(10),
    txn_typ VARCHAR(3),
    stk_hld VARCHAR(1),
    spl_idy VARCHAR(10),
    sal_typ VARCHAR(3),
    avt_dat DATE,
    avt_tim VARCHAR(10),
    mbl_ody VARCHAR(10),
