-- Table: dkcontrl (Migrated from DKCONTRL.DBF)
DROP TABLE IF EXISTS dkcontrl CASCADE;
CREATE TABLE dkcontrl (
    fname VARCHAR(200),
    filsize BIGINT,
    fdate DATE,
    ftime VARCHAR(10),
    fattrib VARCHAR(5),
    cprsname VARCHAR(12),
    cprssize BIGINT,
    expndsize BIGINT,
    filfound BOOLEAN,
    dest144 INTEGER,
    dest12 INTEGER,
    dest720 INTEGER,
    destnet INTEGER,
    destweb INTEGER,
    setupfile BOOLEAN,
    extrafile BOOLEAN,
    extratype VARCHAR(10),
    cprsflag BOOLEAN,
    compress BOOLEAN,
    parent VARCHAR(12),
    splitfile BOOLEAN,
    uniqueid VARCHAR(14),
    version VARCHAR(12),
    language VARCHAR(12),
    target VARCHAR(40),
    pmgroup BOOLEAN,
    descript VARCHAR(100),
    command VARCHAR(100),
    icon VARCHAR(80),
    register BOOLEAN,
    servertype INTEGER,
    netaddress VARCHAR(100),
    protocol VARCHAR(20),
    authentica INTEGER,
    instlocal BOOLEAN,
    uses TEXT,
    regaction TEXT,
    instaction TEXT,
    cabfname VARCHAR(64),
    cabdefurl TEXT,
    cabinffile VARCHAR(64),
    filepath TEXT,
    infclass VARCHAR(25),
    refkey VARCHAR(20),
    vital BOOLEAN,
    readonly BOOLEAN,
    shared BOOLEAN,
    system BOOLEAN,
    regkey VARCHAR(20),
    vfpspecial BOOLEAN,
    customact TEXT,
    regdata TEXT,
    shortfname VARCHAR(12),
    neverrmv BOOLEAN
