    frm_dat DATE,
    end_dat DATE,
    min_qty NUMERIC(15, 3),
    min_pcg NUMERIC(4, 2),
    min_val NUMERIC(15, 2),
    min_vol NUMERIC(15, 3),
    max_qty NUMERIC(15, 3),
    max_pcg NUMERIC(4, 2),
    max_val NUMERIC(15, 2),
    max_vol NUMERIC(15, 3),
    prd_idy VARCHAR(10),
    bat_idy VARCHAR(10),
    rat_idy VARCHAR(1),
    pro_rat INTEGER,
    inc_typ VARCHAR(10),
    txn_idy VARCHAR(10),
    prd_cat VARCHAR(25),
    sal_col VARCHAR(1),
    _nullflags TEXT
);

-- No records found in SIC.DBF

