-- Table: sku (Migrated from SKU.dbf)
DROP TABLE IF EXISTS sku CASCADE;
CREATE TABLE sku (
    grp_cat VARCHAR(26),
    grp_cls VARCHAR(26),
    prd_nme VARCHAR(31),
    alt_idy VARCHAR(34),
    brd_nme VARCHAR(11),
    prd_pck VARCHAR(14),
    prd_pkt VARCHAR(14),
    pur_rat NUMERIC(26, 4),
    pur_tax NUMERIC(32, 4),
    pur_dis NUMERIC(30, 4),
    sal_rat NUMERIC(22, 4),
    sal_tax NUMERIC(28, 4),
    sal_dis NUMERIC(25, 4),
    mrp_rat NUMERIC(18, 4),
    vol_wgt NUMERIC(26, 4),
    prd_uom VARCHAR(22),
    sub_unt BIGINT,
    cmp_idy VARCHAR(19),
    stk_typ VARCHAR(8),
    age INTEGER,
    brw_seq BIGINT,
    sht_nme VARCHAR(9)
);

