-- Table: snv (Migrated from SNV.DBF)
DROP TABLE IF EXISTS snv CASCADE;
CREATE TABLE snv (
    inv_idy VARCHAR(10),
    inv_dat DATE,
    prd_idy VARCHAR(10),
    txn_typ VARCHAR(3),
    shl_idy VARCHAR(10),
    pck_idy VARCHAR(10),
    i_shl_nos BIGINT,
    i_pck_nos BIGINT,
    r_shl_nos BIGINT,
    r_pck_nos BIGINT,
    d_shl_nos BIGINT,
    d_pck_nos BIGINT,
    dp_shl_nos BIGINT,
    dp_pck_nos BIGINT,
    dep_amt NUMERIC(15, 2),
    brk_shl BIGINT,
    brk_pck BIGINT,
    txn_dat DATE,
    txn_idy VARCHAR(10),
    cst_idy VARCHAR(10),
    stk_upd VARCHAR(1),
    prd_upc INTEGER,
    prd_pck VARCHAR(15),
    smn_idy VARCHAR(10),
    rou_idy VARCHAR(15),
    s_shl_nos BIGINT,
    s_pck_nos BIGINT,
    snv_typ VARCHAR(20),
    snv_rmk VARCHAR(100),
    n_shl_nos BIGINT,
    n_pck_nos BIGINT,
    _nullflags TEXT
);

