-- Table: obrd (Migrated from obrd.DBF)
DROP TABLE IF EXISTS obrd CASCADE;
CREATE TABLE obrd (
    prd_idy VARCHAR(10),
    bat_idy VARCHAR(10),
    bat_nme VARCHAR(20),
    prd_pdr NUMERIC(15, 2),
    prd_sdr NUMERIC(15, 2),
    prd_mrp NUMERIC(15, 2),
    prd_qty NUMERIC(15, 3),
    brd_dom DATE,
    brd_doe DATE,
    p_inc_dis NUMERIC(15, 2),
    s_inc_dis NUMERIC(15, 2),
    p_pur_vat NUMERIC(10, 2),
    p_crt_rnt NUMERIC(10, 2),
    p_crt_vat NUMERIC(10, 2),
    p_tot_vat NUMERIC(10, 2),
    pur_lpp NUMERIC(15, 2),
    u_pur_lpp NUMERIC(10, 2),
    s_sal_vat NUMERIC(10, 2),
    s_crt_rnt NUMERIC(10, 2),
    s_crt_vat NUMERIC(10, 2),
    s_tot_vat NUMERIC(10, 2),
    sal_lpp NUMERIC(15, 2),
    u_sal_lpp NUMERIC(10, 2),
    sku_sbu INTEGER,
    b_crt_rat NUMERIC(10, 2),
    b_crt_dis NUMERIC(10, 2),
    b_pur_tax NUMERIC(10, 2),
    b_sal_tax NUMERIC(10, 2),
    _nullflags TEXT
);

